import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { Alert, Button, Field, Input, LoadingBar, Select, Stack, Text } from '@grafana/ui';
import { AppEvents } from '@grafana/data';
import { getAppEvents } from '@grafana/runtime';
import { getDataSources, getFolders, importDashboard } from '../api/grafana';
import { getTemplateJson } from '../api/templates';
import { DatasourceMapper } from './DatasourceMapper';
import { SimpleModal } from './SimpleModal';
import { VariableField } from './VariableField';
import type {
  DatasourceMapping,
  GrafanaDashboard,
  GrafanaDataSource,
  GrafanaFolder,
  TemplateMetadata,
  TemplateVariable,
} from '../types';
import { navigateToPath } from '../utils/navigation';

interface Props {
  templateId: string;
  metadata: TemplateMetadata;
  variables: TemplateVariable[];
  onDismiss: () => void;
}

type Step = 'details' | 'datasources' | 'variables' | 'importing';

interface VariableOverrideState {
  useCustom: boolean;
  value: string | string[];
}

export function ImportModal({ templateId, metadata, variables, onDismiss }: Props) {
  const appEvents = getAppEvents();

  const datasourceVariables = useMemo(
    () => variables.filter((variable) => variable.type === 'datasource'),
    [variables]
  );
  const configurableVariables = useMemo(
    () => variables.filter((variable) => variable.type !== 'datasource'),
    [variables]
  );

  const [dashboardName, setDashboardName] = useState(metadata.title);
  const [folderUid, setFolderUid] = useState('');
  const [variableOverrides, setVariableOverrides] = useState<Record<string, VariableOverrideState>>(() =>
    buildInitialOverrides(configurableVariables)
  );
  const [datasourceVariableOverrides, setDatasourceVariableOverrides] = useState<Record<string, VariableOverrideState>>(
    () => buildInitialOverrides(datasourceVariables)
  );
  const [datasourceMappings, setDatasourceMappings] = useState<DatasourceMapping[]>([]);

  const [folders, setFolders] = useState<GrafanaFolder[]>([]);
  const [dashboard, setDashboard] = useState<GrafanaDashboard | null>(null);
  const [availableDatasources, setAvailableDatasources] = useState<GrafanaDataSource[]>([]);
  const [datasourceLoadError, setDatasourceLoadError] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [step, setStep] = useState<Step>('details');
  const [importing, setImporting] = useState(false);

  const folderOptions = useMemo(
    () => [{ label: 'General', value: '' }, ...folders.map((folder) => ({ label: folder.title, value: folder.uid }))],
    [folders]
  );

  const loadModalData = useCallback(async () => {
    setLoading(true);
    setError(null);

    try {
      const [templateDashboard, availableFolders] = await Promise.all([getTemplateJson(templateId), getFolders()]);

      setDashboard(templateDashboard);
      setFolders(availableFolders);
    } catch (loadError) {
      setError(loadError instanceof Error ? loadError.message : 'Failed to load template data');
    } finally {
      setLoading(false);
    }

    getDataSources()
      .then((datasources) => {
        setAvailableDatasources(datasources);
        setDatasourceLoadError(null);
      })
      .catch((loadError) => {
        setAvailableDatasources([]);
        setDatasourceLoadError(
          loadError instanceof Error ? loadError.message : 'Failed to load datasources from Grafana'
        );
      });
  }, [templateId]);

  useEffect(() => {
    loadModalData();
  }, [loadModalData]);

  const hasAllDatasourceMappingsSelected = datasourceMappings.every((mapping) => Boolean(mapping.localUid));
  const datasourceVariableIssues = datasourceVariables.filter((variable) =>
    shouldBlockImportForVariable(variable, datasourceVariableOverrides[variable.name])
  );
  const variableIssues = configurableVariables.filter((variable) =>
    shouldBlockImportForVariable(variable, variableOverrides[variable.name])
  );

  const handleImport = async () => {
    if (!dashboard) {
      return;
    }

    setImporting(true);
    setStep('importing');
    setError(null);

    try {
      const result = await importDashboard(
        dashboard,
        {
          dashboardName,
          folderUid,
          variables: buildImportVariablePayload(variableOverrides, datasourceVariableOverrides),
          datasourceMappings,
        },
        variables,
        metadata
      );

      appEvents.publish({
        type: AppEvents.alertSuccess.name,
        payload: [`Dashboard "${dashboardName}" imported successfully.`],
      });

      onDismiss();
      navigateToPath(result.url);
    } catch (importError) {
      const message = getImportErrorMessage(importError);
      setError(message);
      setStep('variables');

      appEvents.publish({
        type: AppEvents.alertError.name,
        payload: ['Import failed', message],
      });
    } finally {
      setImporting(false);
    }
  };

  return (
    <SimpleModal title={`Import: ${metadata.title}`} onDismiss={onDismiss}>
      {loading && (
        <Stack direction="column" gap={1}>
          <LoadingBar width={320} />
          <Text color="secondary">Loading template data...</Text>
        </Stack>
      )}

      {!loading && error && (
        <Alert title="Error" severity="error" style={{ marginBottom: '16px' }}>
          {error}
        </Alert>
      )}

      {!loading && !error && step === 'details' && (
        <Stack direction="column" gap={2}>
          <Text color="secondary">Choose the dashboard name and the Grafana folder before importing the template.</Text>

          <Field label="Dashboard name" required>
            <Input value={dashboardName} onChange={(event) => setDashboardName(event.currentTarget.value)} />
          </Field>

          <Field label="Folder">
            <Select
              options={folderOptions}
              value={folderOptions.find((option) => option.value === folderUid)}
              onChange={(item) => setFolderUid(String(item.value ?? ''))}
            />
          </Field>

          <Stack justifyContent="flex-end" gap={2}>
            <Button variant="secondary" onClick={onDismiss}>
              Cancel
            </Button>
            <Button variant="primary" onClick={() => setStep('datasources')} disabled={!dashboardName.trim()}>
              Next: Datasources
            </Button>
          </Stack>
        </Stack>
      )}

      {!loading && !error && step === 'datasources' && dashboard && (
        <Stack direction="column" gap={2}>
          <DatasourceMapper
            dashboard={dashboard}
            requiredDatasources={metadata.requiredDatasources}
            mappings={datasourceMappings}
            onChange={setDatasourceMappings}
          />

          {datasourceVariables.length > 0 && (
            <Stack direction="column" gap={2}>
              <Text variant="h5">Datasource variables from template</Text>
              <Text color="secondary">
                Datasource variables are kept as-is by default. Enable a custom override only when you want to replace
                the datasource already configured in the template.
              </Text>

              {datasourceVariables.map((variable) => {
                const override = datasourceVariableOverrides[variable.name];
                const exactMatches = availableDatasources.filter((datasource) =>
                  matchesDatasourceType(datasource.type, variable.datasourceType ?? '')
                );
                const datasourcesToShow =
                  exactMatches.length > 0 || !variable.datasourceType ? exactMatches : availableDatasources;

                return (
                  <div
                    key={variable.name}
                    style={{
                      padding: '12px',
                      border: '1px solid var(--grafana-border-weak, #2f3440)',
                      borderRadius: '8px',
                    }}
                  >
                    <Stack direction="column" gap={1}>
                      <Text>
                        <strong>{variable.label || variable.name}</strong>
                      </Text>
                      <Text color="secondary">Current template datasource: {getVariablePreviewValue(variable)}</Text>
                      {variable.datasourceType && (
                        <Text color="secondary">Expected datasource type: {variable.datasourceType}</Text>
                      )}

                      <label style={{ display: 'inline-flex', alignItems: 'center', gap: '8px' }}>
                        <input
                          type="checkbox"
                          checked={override?.useCustom ?? false}
                          onChange={(event) =>
                            setDatasourceVariableOverrides((current) => ({
                              ...current,
                              [variable.name]: {
                                ...(current[variable.name] ?? buildInitialOverride(variable)),
                                useCustom: event.currentTarget.checked,
                              },
                            }))
                          }
                        />
                        <span>Use custom datasource</span>
                      </label>

                      {(override?.useCustom ?? false) && (
                        <select
                          value={typeof override.value === 'string' ? override.value : override.value[0] ?? ''}
                          onChange={(event) =>
                            setDatasourceVariableOverrides((current) => ({
                              ...current,
                              [variable.name]: {
                                ...(current[variable.name] ?? buildInitialOverride(variable)),
                                value: event.currentTarget.value,
                              },
                            }))
                          }
                          style={{
                            minHeight: '40px',
                            borderRadius: '6px',
                            padding: '0 12px',
                            background: 'var(--grafana-input-bg, #111217)',
                            color: 'var(--grafana-input-text, #ffffff)',
                            border: '1px solid var(--grafana-border-strong, #3f4552)',
                          }}
                        >
                          <option value="">Select local datasource</option>
                          {datasourcesToShow.map((datasource) => (
                            <option key={datasource.uid} value={datasource.uid}>
                              {datasource.name} ({datasource.type})
                              {datasource.isDefault ? ' [default]' : ''}
                            </option>
                          ))}
                        </select>
                      )}
                    </Stack>
                  </div>
                );
              })}
            </Stack>
          )}

          {!hasAllDatasourceMappingsSelected && (
            <Alert title="Select all datasources before continuing" severity="warning">
              Every required datasource or datasource reference in the template must be mapped to an available datasource
              in this Grafana instance.
            </Alert>
          )}

          {datasourceVariableIssues.length > 0 && (
            <Alert title="Complete datasource variable overrides before continuing" severity="warning">
              Fill every datasource variable where `Use custom datasource` is enabled.
            </Alert>
          )}

          {datasourceLoadError && (
            <Alert title="Could not load datasource choices" severity="warning">
              {datasourceLoadError}
            </Alert>
          )}

          <Stack justifyContent="flex-end" gap={2}>
            <Button variant="secondary" onClick={() => setStep('details')}>
              Back
            </Button>
            <Button
              variant="primary"
              onClick={() => setStep('variables')}
              disabled={!hasAllDatasourceMappingsSelected || datasourceVariableIssues.length > 0}
            >
              Next: Variables
            </Button>
          </Stack>
        </Stack>
      )}

      {!loading && !error && step === 'variables' && (
        <Stack direction="column" gap={2}>
          <Text color="secondary">
            Template variables keep their current values by default. Enable `Use custom value` only for the variables you
            want to override during import.
          </Text>

          {configurableVariables.length === 0 && (
            <Alert title="No non-datasource template variables detected" severity="info">
              This template will keep all variable values already stored in the dashboard JSON.
            </Alert>
          )}

          {configurableVariables.map((variable) => {
            const override = variableOverrides[variable.name] ?? buildInitialOverride(variable);

            return (
              <div
                key={variable.name}
                style={{
                  padding: '12px',
                  border: '1px solid var(--grafana-border-weak, #2f3440)',
                  borderRadius: '8px',
                }}
              >
                <Stack direction="column" gap={1.5}>
                  <Text>
                    <strong>{variable.label || variable.name}</strong> ({variable.type})
                  </Text>
                  <Text color="secondary">Current template value: {getVariablePreviewValue(variable)}</Text>
                  {variable.query && <Text color="secondary">Query: {variable.query}</Text>}
                  {variable.options?.length ? (
                    <Text color="secondary">Available options: {variable.options.join(', ')}</Text>
                  ) : null}

                  <label style={{ display: 'inline-flex', alignItems: 'center', gap: '8px' }}>
                    <input
                      type="checkbox"
                      checked={override.useCustom}
                      onChange={(event) =>
                        setVariableOverrides((current) => ({
                          ...current,
                          [variable.name]: {
                            ...(current[variable.name] ?? buildInitialOverride(variable)),
                            useCustom: event.currentTarget.checked,
                          },
                        }))
                      }
                    />
                    <span>Use custom value</span>
                  </label>

                  {override.useCustom && (
                    <VariableField
                      variable={variable}
                      value={override.value}
                      onChange={(nextValue) =>
                        setVariableOverrides((current) => ({
                          ...current,
                          [variable.name]: {
                            ...(current[variable.name] ?? buildInitialOverride(variable)),
                            value: nextValue,
                          },
                        }))
                      }
                    />
                  )}
                </Stack>
              </div>
            );
          })}

          {variableIssues.length > 0 && (
            <Alert title="Complete variable overrides before importing" severity="warning">
              Every required variable without a preset template value must either keep a valid template value or use a
              custom override.
            </Alert>
          )}

          <Stack justifyContent="flex-end" gap={2}>
            <Button variant="secondary" onClick={() => setStep('datasources')}>
              Back
            </Button>
            <Button variant="primary" icon="import" onClick={handleImport} disabled={importing || variableIssues.length > 0}>
              {importing ? 'Importing...' : 'Import dashboard'}
            </Button>
          </Stack>
        </Stack>
      )}

      {step === 'importing' && (
        <div style={{ padding: '24px 0' }}>
          <Stack direction="column" gap={1} alignItems="center">
            <LoadingBar width={320} />
            <Text color="secondary">Importing dashboard...</Text>
          </Stack>
        </div>
      )}
    </SimpleModal>
  );
}

function buildInitialOverrides(variables: TemplateVariable[]): Record<string, VariableOverrideState> {
  return Object.fromEntries(variables.map((variable) => [variable.name, buildInitialOverride(variable)]));
}

function buildInitialOverride(variable: TemplateVariable): VariableOverrideState {
  return {
    useCustom: variable.required && !hasPresetVariableValue(variable),
    value: variable.default ?? (variable.multi ? [] : ''),
  };
}

function hasPresetVariableValue(variable: TemplateVariable): boolean {
  return Boolean(variable.default && String(variable.default).trim());
}

function hasValue(value: string | string[]): boolean {
  return Array.isArray(value) ? value.length > 0 : Boolean(value && value.trim());
}

function shouldBlockImportForVariable(
  variable: TemplateVariable,
  override: VariableOverrideState | undefined
): boolean {
  if (!override?.useCustom) {
    return variable.required && !hasPresetVariableValue(variable);
  }

  return !hasValue(override.value);
}

function buildImportVariablePayload(
  variableOverrides: Record<string, VariableOverrideState>,
  datasourceVariableOverrides: Record<string, VariableOverrideState>
): Record<string, string | string[]> {
  return Object.fromEntries(
    [...Object.entries(variableOverrides), ...Object.entries(datasourceVariableOverrides)]
      .filter(([, override]) => override.useCustom)
      .map(([name, override]) => [name, override.value])
  );
}

function getVariablePreviewValue(variable: TemplateVariable): string {
  if (variable.default && variable.default.trim()) {
    return variable.default;
  }

  if (variable.type === 'custom' && variable.options?.length) {
    return variable.options.join(', ');
  }

  if (variable.type === 'query' && variable.query) {
    return 'Template query result';
  }

  return 'No preset value';
}

function matchesDatasourceType(actualType: string, expectedType: string): boolean {
  const normalizedActual = actualType.trim().toLowerCase();
  const normalizedExpected = expectedType.trim().toLowerCase();

  if (!normalizedExpected) {
    return true;
  }

  return normalizedActual === normalizedExpected || normalizedActual.includes(normalizedExpected);
}

function getImportErrorMessage(importError: unknown): string {
  if (importError instanceof Error && importError.message.trim()) {
    return importError.message;
  }

  if (typeof importError !== 'object' || importError === null) {
    return 'Import failed';
  }

  const fetchLikeError = importError as {
    status?: number;
    data?: { message?: string; error?: string };
    statusText?: string;
  };

  const backendMessage =
    fetchLikeError.data?.message?.trim() || fetchLikeError.data?.error?.trim() || fetchLikeError.statusText?.trim();

  if (fetchLikeError.status === 403) {
    return (
      backendMessage ||
      'Grafana denied dashboard creation for this user. Viewers can only import when their folder or dashboard permissions allow creating dashboards in the selected location.'
    );
  }

  return backendMessage || 'Import failed';
}
